  ('retired-10ced7e2-moex-00127', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-c6520f59', 'sub-retired-10ced7e2-07', NULL, 'essay', '各國人事機構的設置有所謂部內制、部外制和折衷制等分類，請論述其
意義，並各舉一國為例說明。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "8b8990475a1d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0308", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "各國人事制度", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00128', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["今天氣溫驟降，乍暖還寒，他雖已穿上外套，仍然覺得「不寒而慄」", "疫情趨緩，管制措施取消，週末遊樂場重新開放，人潮「不絕如縷」", "全面網路教學，不像在教室上課，老師可以直接對學生「移樽就教」", "網路上有各種消息與傳聞，需仔細辨明查證，是否只是「空穴來風」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00129', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「近代民族國家的形成，無疑促進了各國（特別是各小國）從過去歷史中去尋求民 族文化及其經典系列的努力。能夠尋找出這樣一個系列，並且讓世界各國接受與承 認，無疑可以增進民族的尊嚴與自豪。近代所形成的各級教育體系，也促進了這種 作用。各國在語言教育及人文教育中，都會把經典作品按其程度的深淺，選入各級 教育的教材中，以便讓他們的人民，學習到這一『傳統』，從『認識』中得到『認 同』，並由此而獲得『民族感情』。」 根據上文，下列敘述何者最符合作者立論？', '["一個民族國家的人文經典，時常需要從歷史中找尋，同時透過後天教育體制來發 展與建構", "近代民族國家的形成，需要受到世界各國的接受與承認，所以吸收西方思想與方 法是必要的歷程", "民族感情跟民族認同有關，民族認同又與傳統有關，因此應該積極地講究復古， 因為復古即傳統", "各級教育有形塑民族人文經典的功能，因此尚未成熟的作品，基於保護和提攜， 還是應該選入教材"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00130', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「李漁說南方人吃切麵，把油鹽醬醋等作料，都下到麵湯裡，他對這種吃麵的辦法 期期以為不可，『湯有味而麵無味，是人所重者不在麵而在湯，與未嘗食麵等也。 予則不然，以調和諸物，盡歸於麵，麵具五味而湯獨清，如此方是食麵，非飲湯也。』 李漁自製『五香麵』，所謂的『五香』是醬、醋、椒末、芝麻屑，另加上焯筍或煮 蕈煮蝦的高湯；椒末、芝麻屑拌入麵裡，醬、醋、高湯作為和麵之水，拌勻，揉薄， 切細，如此一來美味盡在麵條之中。」 根據上文，符合李漁製麵的態度是：', '["煮湯麵時的調味越多樣越好", "油鹽醬醋的比例可隨性任意", "湯麵的關鍵在高湯，需精燉熬湯", "作麵時需調和醬料高湯和入麵中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00131', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '甲若接受乙所提出的條件，則必須移居高雄；而甲若移居高雄，則不能留在臺中。 甲若接受丙所提出的條件，則必須留在臺中。甲必須接受乙或丙所提出的條件。因 此，甲必須移居高雄或留在臺中。 根據上文，下列選項何者正確？', '["甲必須選擇乙方所提出的條件，選擇移居高雄或留居臺中", "甲必須選擇丙方所提出的條件，選擇移居高雄或留居臺中", "甲必須只能接受乙或丙的條件，選擇移居高雄或留居臺中", "甲可以不接受乙和丙的條件，既不移居高雄也不移居臺中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL),
  ('retired-10ced7e2-moex-00132', 'retired-10ced7e2', 'retired-10ced7e2-moex-112-13504c0c', 'sub-retired-10ced7e2-02', NULL, 'single_choice', '「高雄百貨業鉅子吳耀庭（1926年生）曾自述他十七歲那年，月薪從十七元跳到四 十元，於是身懷『巨款』，很神氣走進吉井百貨公司三樓，要幫母親買禮物。他問 女店員，『這面鏡子要多少錢？』女店員打量他一番，然後冷笑一聲『哼』！這聲 『哼』深深刺傷吳耀庭，他發願要在高雄創建一家超棒的百貨公司。戰後聞名南臺 灣的大新百貨公司，因而被『吉井』店員的惡劣態度刺激誕生。」 根據上文，下列選項最適合形容吳耀庭的是：', '["寶劍鋒從磨礪出，梅花香自苦寒來", "天生我材必有用，千金散盡還復來", "嘗將冷眼觀螃蟹，看你橫行到幾時", "翻手作雲覆手雨，紛紛輕薄何須數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:18+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "135", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "人事行政"}'::jsonb, NULL)
